export const atlasCategories: string[] = Array.from(new Set(atlasEntries.map((e) => e.category)));

/** Busca uma entrada do Atlas pelo seu id. */
export function getAtlasEntry(id: string): AtlasEntry | undefined {
  return atlasEntries.find((e) => e.id === id);
}

/** Ordem de exibição das categorias no índice do Atlas. */
export const atlasCategoryOrder: string[] = [
  "Endourologia",
  "Próstata",
  "Oncologia",
  "Funcional",
  "Andrologia / Fertilidade",
  "Andrologia / Prótese",
  "Andrologia / Peyronie",
  "Andrologia / Estética",
  "Andrologia / Imagem",
  "Estética Genital",
  "Saúde do Homem",
  "Urgência",
];

/** Retorna as entradas agrupadas por categoria, na ordem definida. */
export function atlasGroupedByCategory(): { category: string; entries: AtlasEntry[] }[] {
  const groups = new Map<string, AtlasEntry[]>();
  for (const e of atlasEntries) {
    if (!groups.has(e.category)) groups.set(e.category, []);
    groups.get(e.category)!.push(e);
  }
  const ordered = atlasCategoryOrder.filter((c) => groups.has(c));
  for (const c of Array.from(groups.keys())) if (!ordered.includes(c)) ordered.push(c);
  return ordered.map((category) => ({
    category,
    entries: groups.get(category)!.slice().sort((a, b) => a.name.localeCompare(b.name, "pt-BR")),
  }));
}

